SELECT ORDERH.REF, ORDERH.CRNOTE, ORDERH.SELLCO, ORDERH.ORDDATE, ORDERH.CUSTCODE, ORDERH.SEQTYPE, ORDERH.CURRRATE, ORDERH.VALNETBASE, ORDERH.TOTCOST, ORDERH.INSTATUS, ORDERH.OHINVREF, ORDERH.OHINVDATE, ORDERH.UF_ACCHAND, ORDERI.REF, ORDERI.PRODUCT, ORDERI.DESC1, ORDERI.DESC2, ORDERI.DESC3, ORDERI.QUANTITY, ORDERI.PRICE, ORDERI.COST, ORDERI.TOTNET, ORDERH.TERR, ORDERH.COMPANY, SUBSTRING(ORDERH.TERR, 3, 2) AS Terr_Mid, CASE WHEN ORDERH.CRNOTE = 1 OR ORDERH.CRNOTE = TRUE THEN -1 * (ORDERI.PRICE / ORDERH.CURRRATE * ORDERI.QUANTITY) ELSE (ORDERI.PRICE / ORDERH.CURRRATE * ORDERI.QUANTITY) END AS Val_GBP, CASE WHEN ORDERH.CRNOTE = 1 THEN -1 * (ORDERI.QUANTITY) ELSE (ORDERI.QUANTITY) END AS Tot_Qty, CASE WHEN ORDERH.CRNOTE = 1 THEN -1 * (ORDERI.COST * ORDERI.QUANTITY) ELSE (ORDERI.COST * ORDERI.QUANTITY) END AS Tot_Cost FROM NISAINT_CS\ORDERH ORDERH, NISAINT_CS\ORDERI ORDERI WHERE ORDERH.REF = ORDERI.REF AND ((ORDERH.OHINVDATE>={d '2023-01-01'}))
